#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        char first,second,third, x, y;
        scanf(" %c %c %c", &first, &second, &third);
        scanf(" %c %c", &x, &y);
        char ans;
        if(first==x || first==y) ans=first;
        else if(second==x || second==y) ans=second;
        else ans=third;
        printf("%c\n", ans);
    }
    return 0;
}

