#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        first = next(it); second = next(it); third = next(it)
        x = next(it); y = next(it)
        if first == x or first == y:
            out.append(first)
        elif second == x or second == y:
            out.append(second)
        else:
            out.append(third)
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

